INSERT OR IGNORE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('猎人 Hunter', '渔轮', '纺车式', '猎人 Hunter', 'Hunter 80S', '泽曼渔具公司（Zeiman） 的工程师开发的名为‘猎人’的全新纺车轮系列，机身采用极简的轻量化设计，并为机械装置提供出色的防水保护。特殊的转子设计和控制系统，让该系列渔线轮顺滑性能卓著。创新的线轴几何形状实现更高的抛投效率，泄力系统确保应对负荷变化的响应一致性，使您能够快速适应变化的作钓条件。系列包括高速型号和大功率型号。', '4.7:1', 0, '', '1.04', 0, '8000', '纺车式', '18.5kg', 0, '', '12g', 0, '22', '', '', '', '', 0, '54.45', '7499.6', '49.13kg', 0, '💧');
